import{_ as p,c as M}from"./app.f21a7cce.js";const B={},T=M('<h1 id="_47-\u8BB2-\u7528\u673A\u5668\u8BBE\u8BA1\u6D4B\u8BD5\u7528\u4F8B-\u57FA\u4E8E\u6A21\u578B\u7684\u6D4B\u8BD5" tabindex="-1"><a class="header-anchor" href="#_47-\u8BB2-\u7528\u673A\u5668\u8BBE\u8BA1\u6D4B\u8BD5\u7528\u4F8B-\u57FA\u4E8E\u6A21\u578B\u7684\u6D4B\u8BD5" aria-hidden="true">#</a> 47 \u8BB2\uFF1A\u7528\u673A\u5668\u8BBE\u8BA1\u6D4B\u8BD5\u7528\u4F8B\uFF1A\u57FA\u4E8E\u6A21\u578B\u7684\u6D4B\u8BD5</h1><p>\u4F60\u597D\uFF0C\u6211\u662F\u8339\u70B3\u665F\u3002\u4ECA\u5929\u6211\u548C\u4F60\u5206\u4EAB\u7684\u4E3B\u9898\u662F\uFF1A\u7528\u673A\u5668\u8BBE\u8BA1\u6D4B\u8BD5\u7528\u4F8B\u4E4B\u57FA\u4E8E\u6A21\u578B\u7684\u6D4B\u8BD5\u201D\u3002</p><p>\u6211\u5728\u524D\u9762 4 \u7BC7\u6587\u7AE0\u4E2D\uFF0C\u548C\u4F60\u5206\u4EAB\u7684\u63A2\u7D22\u5F0F\u6D4B\u8BD5\u3001\u6D4B\u8BD5\u9A71\u52A8\u5F00\u53D1 TDD\u3001\u7CBE\u51C6\u6D4B\u8BD5\uFF0C\u4EE5\u53CA\u6E17\u900F\u6D4B\u8BD5\u7684\u5185\u5BB9\uFF0C\u4F60\u662F\u5426\u5DF2\u7ECF\u638C\u63E1\u4E86\u5462\uFF1F\u6709\u6CA1\u6709\u5C1D\u8BD5\u5C06\u8FD9\u4E9B\u6BD4\u8F83\u65B0\u7684\u7406\u5FF5\u7528\u5230\u4F60\u7684\u5DE5\u7A0B\u9879\u76EE\u4E2D\u5462\uFF1F\u5982\u679C\u4F60\u5728\u5E94\u7528\u7684\u8FC7\u7A0B\u4E2D\uFF0C\u9047\u5230\u4E86\u4EFB\u4F55\u95EE\u9898\uFF0C\u4E5F\u6B22\u8FCE\u7ED9\u6211\u7559\u8A00\u4E00\u8D77\u8BA8\u8BBA\u3002</p><p>\u90A3\u4E48\uFF0C\u73B0\u5728\u6211\u4EEC\u5C31\u6B63\u5F0F\u5F00\u59CB\u6D4B\u8BD5\u65B0\u6280\u672F\u7CFB\u5217\u7684\u6700\u540E\u4E00\u4E2A\u8BDD\u9898\uFF1A\u57FA\u4E8E\u6A21\u578B\u7684\u6D4B\u8BD5\u3002</p><p>\u53EF\u4EE5\u8BF4\uFF0C\u8F6F\u4EF6\u6D4B\u8BD5\u662F\u4E00\u6B3E\u8F6F\u4EF6\u4EA7\u54C1\u8D28\u91CF\u7684\u6700\u540E\u4E00\u9053\u9632\u7EBF\uFF0C\u662F\u4EA7\u54C1\u4E0A\u7EBF\u524D\u5FC5\u4E0D\u53EF\u5C11\u3001\u6700\u91CD\u8981\u7684\u4E00\u4E2A\u73AF\u8282\u3002\u6BCF\u4E00\u6B3E\u9AD8\u8D28\u91CF\u7684\u8F6F\u4EF6\u4EA7\u54C1\u80CC\u540E\uFF0C\u90FD\u8574\u542B\u4E86\u5927\u91CF\u7684\u6D4B\u8BD5\u5DE5\u4F5C\u3002\u800C\u4E14\uFF0C\u8FD9\u4E9B\u6D4B\u8BD5\u5DE5\u4F5C\u5F88\u53EF\u80FD\u662F\u6574\u4E2A\u8F6F\u4EF6\u5F00\u53D1\u8FC7\u7A0B\u4E2D\u6700\u6602\u8D35\u3001\u52B3\u52A8\u6700\u5BC6\u96C6\u7684\u5DE5\u4F5C\u3002</p><p>\u867D\u8BF4\u4ECE\u6700\u7B80\u5355\u7684\u529F\u80FD\u6027\u9ED1\u76D2\u6D4B\u8BD5\uFF0C\u5230\u6D89\u53CA\u5B9A\u7406\u8BC1\u660E\u7684\u590D\u6742\u6D4B\u8BD5\uFF0C\u5DF2\u7ECF\u6709\u5F88\u591A\u79CD\u65B9\u6CD5\u53EF\u4EE5\u5E2E\u52A9\u6211\u4EEC\u63D0\u9AD8\u6D4B\u8BD5\u7684\u53EF\u9760\u6027\u548C\u6709\u6548\u6027\u3002\u4F46\u662F\uFF0C\u5728\u8BBE\u8BA1\u6D4B\u8BD5\u7528\u4F8B\u7684\u8FC7\u7A0B\u4E2D\uFF0C\u603B\u8FD8\u662F\u5B58\u5728\u7740\u8FD9\u6837\u90A3\u6837\u7684\u95EE\u9898\uFF0C\u4F7F\u5F97\u8F6F\u4EF6\u6D4B\u8BD5\u7684\u7ED3\u679C\u6CA1\u90A3\u4E48\u7406\u60F3\u3002</p><p>\u4E3A\u6B64\uFF0C\u6211\u4EEC\u65B0\u5F15\u5165\u4E86\u57FA\u4E8E\u6A21\u578B\u7684\u6D4B\u8BD5\uFF0C\u5373 Model-Based-Testing\uFF0C\u7B80\u79F0 MBT\u3002</p><p>MBT\uFF0C\u662F\u81EA\u52A8\u5316\u6D4B\u8BD5\u7684\u4E00\u4E2A\u5206\u652F\u3002\u5B83\u662F\u5C06\u6D4B\u8BD5\u7528\u4F8B\u7684\u8BBE\u8BA1\u4F9D\u6258\u4E8E\u88AB\u6D4B\u7CFB\u7EDF\u7684\u6A21\u578B\uFF0C\u5E76\u57FA\u4E8E\u8BE5\u6A21\u578B\u81EA\u52A8\u751F\u6210\u6D4B\u8BD5\u7528\u4F8B\u7684\u6280\u672F\u3002\u5176\u4E2D\uFF0C\u8FD9\u4E2A\u88AB\u6D4B\u7CFB\u7EDF\u7684\u6A21\u578B\u8868\u793A\u4E86\u88AB\u6D4B\u7CFB\u7EDF\u884C\u4E3A\u7684\u9884\u671F\uFF0C\u4E5F\u53EF\u4EE5\u8BF4\u662F\u4EE3\u8868\u4E86\u6211\u4EEC\u5BF9\u88AB\u6D4B\u7CFB\u7EDF\u7684\u9884\u671F\u3002</p><p>\u4ECE\u8D28\u91CF\u4FDD\u8BC1\u7684\u89D2\u5EA6\u6765\u770B\uFF0C\u6211\u4EEC\u53EF\u4EE5\u5236\u5B9A\u6D4B\u8BD5\u5185\u5BB9\uFF0C\u4F46\u5374\u65E0\u6CD5\u4FDD\u8BC1\u6D4B\u8BD5\u4F1A\u8986\u76D6\u6240\u6709\u53EF\u80FD\u7684\u7EC4\u5408\u3002\u800C MBT \u5219\u5141\u8BB8\u8F6F\u4EF6\u5F00\u53D1\u4EBA\u5458\u548C\u6D4B\u8BD5\u4EBA\u5458\uFF0C\u53EA\u5173\u6CE8\u5EFA\u7ACB\u7CFB\u7EDF\u7684\u6B63\u786E\u6027\u4EE5\u53CA\u6A21\u578B\u7684\u89C4\u8303\u6027\uFF0C\u518D\u901A\u8FC7\u4E13\u95E8\u7684 MBT \u5DE5\u5177\u6839\u636E\u4E0D\u540C\u7684\u6D4B\u8BD5\u7528\u4F8B\u8BBE\u8BA1\u7B56\u7565\u4ECE\u7CFB\u7EDF\u6A21\u578B\u751F\u6210\u53EF\u9760\u7684\u6D4B\u8BD5\u7528\u4F8B\u3002</p><p>\u90A3\u4E48\uFF0CMBT \u7684\u539F\u7406\u662F\u4EC0\u4E48\uFF0C\u800C\u4EC0\u4E48\u6837\u7684\u5E94\u7528\u53C8\u9002\u5408\u8FDB\u884C MBT \u5462\uFF1F\u63A5\u4E0B\u6765\uFF0C\u6211\u5C31\u91CD\u70B9\u4E3A\u4F60\u56DE\u7B54\u8FD9\u4E24\u4E2A\u95EE\u9898\u3002</p><p><strong>MBT \u7684\u57FA\u672C\u539F\u7406</strong></p><p>MBT \u7684\u57FA\u672C\u539F\u7406\u662F\u901A\u8FC7\u5EFA\u7ACB\u88AB\u6D4B\u7CFB\u7EDF\u7684\u8BBE\u8BA1\u6A21\u578B\uFF0C\u7136\u540E\u7ED3\u5408\u4E0D\u540C\u7684\u7B97\u6CD5\u548C\u7B56\u7565\u6765\u904D\u5386\u8BE5\u6A21\u578B\uFF0C\u4EE5\u6B64\u751F\u6210\u6D4B\u8BD5\u7528\u4F8B\u7684\u8BBE\u8BA1\u3002</p><p>\u6211\u7528\u4E0B\u9762\u7684\u4E00\u5F20\u56FE\u7247\uFF0C\u4E3A\u4F60\u63CF\u8FF0\u4E86 MBT \u7684\u8FC7\u7A0B\uFF1A</p><p><img src="https://static001.geekbang.org/resource/image/08/f9/08c3605390ca20c46b63e92f29f375f9.png" alt="MBT\u7684\u4E00\u822C\u8FC7\u7A0B"></p><p>\u5982\u56FE 1 \u6240\u793A\uFF0C\u5F00\u53D1\u8005\u9996\u5148\u6839\u636E\u4EA7\u54C1\u9700\u6C42\u6216\u8005\u8BF4\u660E\u6765\u6784\u5EFA\u6A21\u578B\uFF0C\u7136\u540E\u7ED3\u5408\u6D4B\u8BD5\u5BF9\u8C61\u751F\u6210\u6D4B\u8BD5\u7528\u4F8B\uFF0C\u6D4B\u8BD5\u7528\u4F8B\u9488\u5BF9\u6D4B\u8BD5\u5BF9\u8C61\u6267\u884C\u5B8C\u4E4B\u540E\uFF0C\u751F\u6210\u6D4B\u8BD5\u62A5\u544A\u6BD4\u5BF9\u6D4B\u8BD5\u7ED3\u679C\u3002</p><p>\u63A5\u4E0B\u6765\uFF0C\u6211\u4EE5\u7B80\u5355\u7684\u767B\u5F55\u7CFB\u7EDF\u4E3A\u4F8B\uFF0C\u548C\u4F60\u8BF4\u660E\u5982\u4F55\u5EFA\u6A21\u3002</p><p>\u5F53\u7528\u6237\u8BBF\u95EE\u7F51\u7AD9\u65F6\uFF0C\u7F51\u7AD9\u9700\u8981\u8BC6\u522B\u7528\u6237\u662F\u5426\u5DF2\u7ECF\u767B\u5F55\uFF1A</p><p>\u5982\u679C\u5DF2\u7ECF\u662F\u767B\u5F55\u72B6\u6001\uFF0C\u5219\u8BA9\u7528\u6237\u8FDB\u5165\uFF0C\u7ED3\u675F\u8FD9\u4E00\u5206\u652F\uFF1B \u5982\u679C\u7528\u6237\u8FD8\u6CA1\u6709\u767B\u5F55\uFF0C\u90A3\u4E48\u9875\u9762\u9700\u8981\u8FD4\u56DE\u767B\u5F55\u6846\u7ED9\u7528\u6237\u3002\u7528\u6237\u5728\u767B\u5F55\u6846\u8F93\u5165\u7528\u6237\u540D\u548C\u5BC6\u7801\u540E\uFF0C\u7531\u540E\u53F0\u670D\u52A1\u9A8C\u8BC1\u7528\u6237\u540D\u548C\u5BC6\u7801\u662F\u5426\u6B63\u786E\uFF0C\u5982\u679C\u901A\u8FC7\u9A8C\u8BC1\uFF0C\u5219\u7528\u6237\u767B\u5F55\u6210\u529F\uFF0C\u7ED3\u675F\u5206\u652F\uFF1B\u5426\u5219\uFF0C\u8FD4\u56DE\u9519\u8BEF\u4FE1\u606F\uFF0C\u5E76\u518D\u6B21\u8FD4\u56DE\u767B\u5F55\u6846\u4F9B\u7528\u6237\u767B\u5F55\u3002 \u6839\u636E\u8FD9\u4E2A\u903B\u8F91\uFF0C\u6211\u4EEC\u53EF\u4EE5\u5EFA\u6A21\u5982\u4E0B\uFF1A</p><p><img src="https://static001.geekbang.org/resource/image/7f/95/7fb2ceb31c81046261d59a3c2226a195.png" alt="\u7F51\u7AD9\u767B\u5F55\u7CFB\u7EDF\u5EFA\u6A21"></p><p>\u81F3\u6B64\uFF0C\u6211\u4EEC\u5C31\u5B8C\u6210\u5BF9\u8FD9\u4E2A\u767B\u5F55\u7CFB\u7EDF\u7684\u5EFA\u6A21\u5DE5\u4F5C\u4E86\u3002\u7136\u540E\uFF0C\u6211\u4EEC\u901A\u8FC7\u5177\u8C61\u5316\u88AB\u6D4B\u4EA7\u54C1\u7684\u9700\u6C42\u884C\u4E3A\uFF0C\u518D\u901A\u8FC7\u5DE5\u5177\u6765\u904D\u5386\u6A21\u578B\u4E2D\u7684\u5404\u4E2A\u8DEF\u5F84\uFF0C\u5C31\u53EF\u4EE5\u5F97\u5230\u6211\u4EEC\u9700\u8981\u7684\u6D4B\u8BD5\u7528\u4F8B\u4E86\u3002</p><p>\u6240\u4EE5\uFF0C\u6267\u884C MBT \u7684\u8FC7\u7A0B\u5C31\u597D\u6BD4\u4F60\u628A\u8F6F\u4EF6\u7CFB\u7EDF\u7684\u8BBE\u8BA1\u753B\u4E3A\u4E86\u4E00\u5F20\u7531\u8282\u70B9\u548C\u8FB9\u6784\u6210\u7684\u6570\u636E\u7ED3\u6784\u610F\u4E49\u4E0A\u7684\u201C\u56FE\u201D\uFF0C\u7136\u540E\u901A\u8FC7\u4E00\u5B9A\u7684\u7B97\u6CD5\uFF08\u6BD4\u5982\uFF0C\u6DF1\u5EA6\u904D\u5386\u6216\u8005\u5E7F\u5EA6\u904D\u5386\uFF09\u6765\u5C3D\u53EF\u80FD\u5B8C\u6574\u8986\u76D6\u56FE\u4E2D\u5168\u90E8\u7684\u53EF\u80FD\u8DEF\u5F84\u7684\u8FC7\u7A0B\u3002</p><p>\u800C\u6839\u636E\u88AB\u6D4B\u7CFB\u7EDF\u7684\u7279\u70B9\uFF0C\u6211\u4EEC\u53EF\u4EE5\u521B\u5EFA\u4E0D\u540C\u7C7B\u578B\u7684\u6A21\u578B\u5B8C\u6210 MBT\u3002\u63A5\u4E0B\u6765\uFF0C\u6211\u4EEC\u5C31\u4E00\u8D77\u770B\u770B\u6709\u54EA\u4E9B\u5E38\u7528\u7684 MBT \u6A21\u578B\u5427\u3002</p><p><strong>\u5E38\u7528\u6A21\u578B\u7B80\u4ECB</strong></p><p>\u6839\u636E\u88AB\u6D4B\u7CFB\u7EDF\u672C\u8EAB\u7684\u7279\u70B9\uFF0C\u6211\u4EEC\u5E38\u7528\u7684\u6A21\u578B\u4E3B\u8981\u6709\u9650\u72B6\u6001\u673A\u3001\u72B6\u6001\u56FE\uFF0C\u4EE5\u53CA UML \u4E09\u79CD\u3002\u5176\u4E2D\uFF0C\u6709\u9650\u72B6\u6001\u673A\u548C\u72B6\u6001\u56FE\u6BD4\u8F83\u9002\u5408\u4E8E\u7528\u72B6\u6001\u6216\u8005\u4E8B\u4EF6\u9A71\u52A8\u7684\u7CFB\u7EDF\uFF0C\u800C UML \u6BD4\u8F83\u9002\u5408\u4E8E\u9760\u4E1A\u52A1\u6D41\u7A0B\u9A71\u52A8\u7684\u7CFB\u7EDF\u3002</p><p><strong>\u7B2C\u4E00\uFF0C\u6709\u9650\u72B6\u6001\u673A\u3002</strong></p><p>\u6709\u9650\u72B6\u6001\u673A\u53EF\u4EE5\u5E2E\u52A9\u6D4B\u8BD5\u4EBA\u5458\u6839\u636E\u9009\u4E2D\u7684\u8F93\u5165\u6765\u8BC4\u4F30\u8F93\u51FA\uFF0C\u4E0D\u540C\u7684\u8F93\u5165\u7EC4\u5408\u5BF9\u5E94\u7740\u4E0D\u540C\u7684\u7CFB\u7EDF\u72B6\u6001\u3002</p><p>\u5728\u767B\u5F55\u7CFB\u7EDF\u8FD9\u4E2A\u4F8B\u5B50\u4E2D\uFF0C\u5458\u5DE5\u5728\u672A\u767B\u5F55\u65F6\u7684\u72B6\u6001\u662F\u201C\u672A\u767B\u5F55\u201D\uFF0C\u4E00\u65E6\u767B\u5F55\u6210\u529F\u72B6\u6001\u5C31\u4F1A\u53D8\u4E3A\u201C\u5DF2\u767B\u5F55\u201D\u3002\u5728\u5DF2\u767B\u5F55\u7684\u72B6\u6001\u4E0B\uFF0C\u5458\u5DE5\u53EF\u4EE5\u8BBF\u95EE\u5404\u7C7B\u8D44\u6E90\uFF0C\u4F7F\u7528\u7CFB\u7EDF\u5185\u7684\u5DE5\u5177\u3002</p><p><strong>\u7B2C\u4E8C\uFF0C\u72B6\u6001\u56FE\u3002</strong></p><p>\u72B6\u6001\u56FE\u662F\u6709\u9650\u72B6\u6001\u673A\u7684\u5EF6\u4F38\uFF0C\u7528\u4E8E\u63CF\u8FF0\u7CFB\u7EDF\u7684\u5404\u79CD\u884C\u4E3A\uFF0C\u5C24\u5176\u9002\u7528\u4E8E\u590D\u6742\u4E14\u5B9E\u65F6\u7684\u7CFB\u7EDF\u3002</p><p>\u72B6\u6001\u56FE\u6709\u4E00\u5B9A\u6570\u91CF\u7684\u72B6\u6001\uFF0C\u7CFB\u7EDF\u7684\u884C\u4E3A\u53EF\u4EE5\u4EE5\u4E8B\u4EF6\u7684\u65B9\u5F0F\u6765\u9A71\u52A8\u72B6\u6001\u7684\u53D8\u5316\u3002\u6BD4\u5982\uFF0C\u7F3A\u9677\u7BA1\u7406\u5DE5\u5177\u4E2D\u51FA\u73B0\u4E86\u7F3A\u9677\uFF0C\u5176\u521D\u59CB\u72B6\u6001\u4E3A\u201Cnew\u201D\uFF1B\u7F3A\u9677\u88AB\u5F00\u53D1\u4EBA\u5458\u4FEE\u590D\u540E\uFF0C\u5C31\u5FC5\u987B\u5C06\u5176\u6539\u4E3A\u201CFixed\u201D\uFF1B\u4F46\u662F\uFF0C\u5982\u679C\u6B64\u65F6\u6D4B\u8BD5\u4EBA\u5458\u53D1\u73B0\u7F3A\u9677\u5E76\u672A\u4FEE\u590D\u6216\u8005\u53EA\u662F\u90E8\u5206\u4FEE\u590D\u65F6\uFF0C\u5219\u9700\u5C06\u72B6\u6001\u66F4\u6539\u4E3A\u201CReopen\u201D\uFF08\u91CD\u65B0\u6253\u5F00\uFF09\u3002</p><p>\u72B6\u6001\u56FE\u7684\u8BBE\u8BA1\u65B9\u5F0F\uFF0C\u8981\u6C42\u4E3A\u6BCF\u4E2A\u4E0D\u540C\u7684\u72B6\u6001\u521B\u5EFA\u4E00\u4E2A\u4E8B\u4EF6\u3002</p><p><strong>\u7B2C\u4E09\uFF0CUML\u3002</strong></p><p>UML \u5373\u7EDF\u4E00\u5EFA\u6A21\u8BED\u8A00\uFF0C\u662F\u4E00\u79CD\u6807\u51C6\u5316\u7684\u901A\u7528\u5EFA\u6A21\u8BED\u8A00\u3002UML \u6709\u81EA\u5DF1\u5B9A\u4E49\u7684\u56FE\u5F62\u5E93\uFF0C\u91CC\u9762\u5305\u542B\u4E86\u4E30\u5BCC\u7684\u56FE\u5F62\u7528\u4EE5\u63CF\u8FF0\u7CFB\u7EDF\u3001\u6D41\u7A0B\u7B49\u3002</p><p>UML \u53EF\u4EE5\u901A\u8FC7\u521B\u5EFA\u53EF\u89C6\u5316\u6A21\u578B\uFF0C\u6765\u63CF\u8FF0\u975E\u5E38\u590D\u6742\u7684\u7CFB\u7EDF\u884C\u4E3A\u3002</p><p>\u5F53\u6211\u4EEC\u5B8C\u6210\u88AB\u6D4B\u7CFB\u7EDF\u7684\u5EFA\u6A21\u5DE5\u4F5C\u540E\uFF0C\u63A5\u4E0B\u6765\u5C31\u8981\u5C06\u6A21\u578B\u8F6C\u5316\u4E3A\u53EF\u6267\u884C\u7684\u6D4B\u8BD5\u7528\u4F8B\u4E86\u3002\u8FD9\u4E2A\u8F6C\u6362\u8FC7\u7A0B\uFF0C\u9700\u8981\u501F\u52A9\u5DE5\u5177\u6765\u5B8C\u6210\u3002</p><p>\u56E0\u4E3A\u4E0D\u540C\u9886\u57DF\u7684\u4EA7\u54C1\u98CE\u683C\u8FE5\u5F02\uFF0C\u5176\u4F7F\u7528\u7684\u81EA\u52A8\u5316\u6846\u67B6\u548C\u7F16\u7A0B\u8BED\u8A00\u4E5F\u5404\u4E0D\u76F8\u540C\uFF0C\u6240\u4EE5\u6211\u4EEC\u9700\u8981\u82B1\u8D39\u4E00\u4E9B\u7CBE\u529B\u53BB\u5BFB\u627E\u4E0E\u81EA\u5DF1\u4EA7\u54C1\u5339\u914D\u7684 MBT \u5DE5\u5177\u3002\u5176\u5B9E\uFF0C\u5728\u5F88\u591A\u60C5\u51B5\u4E0B\uFF0C\u6211\u4EEC\u8FD8\u9700\u8981\u6839\u636E\u4EA7\u54C1\u7279\u70B9\uFF0C\u53BB\u81EA\u884C\u5F00\u53D1\u548C\u5B9A\u5236\u5DE5\u5177\u3002</p><p><strong>MBT \u5DE5\u5177\u7B80\u4ECB</strong></p><p>\u8FD9\u91CC\uFF0C\u6211\u4E3A\u4F60\u7F57\u5217\u4E86\u4E00\u4E9B\u5E38\u89C1\u7684 MBT \u5DE5\u5177\uFF0C\u5305\u62EC\uFF1ABPM-X\u3001fMBT\u3001GraphWalker\u3002\u5728\u8FD9\u91CC\uFF0C\u6211\u4E3A\u4F60\u7B80\u5355\u4ECB\u7ECD\u8FD9\u4E9B\u5DE5\u5177\u7684\u76EE\u7684\u662F\uFF0C\u8BA9\u4F60\u53EF\u4EE5\u5BF9 MBT \u5DE5\u5177\u672C\u8EAB\u6709\u4E2A\u611F\u6027\u7684\u8BA4\u8BC6\uFF0C\u8BA9\u4F60\u77E5\u9053\u6B64\u7C7B\u5DE5\u5177\u7684\u5E94\u7528\u573A\u666F\u548C\u4E0A\u4E0B\u6587\u3002\u81F3\u4E8E\u8BF4\u5982\u4F55\u6765\u9009\u62E9\u4F7F\u7528\u8FD9\u4E9B\u5DE5\u5177\uFF0C\u8FD9\u5728\u5F88\u5927\u7A0B\u5EA6\u4E0A\u53D6\u51B3\u4E8E\u88AB\u6D4B\u7CFB\u7EDF\u7684\u7279\u70B9\u3002</p><p><strong>\u7B2C\u4E00\uFF0CBPM-X</strong></p><p>BPM-X \u6839\u636E\u4E0D\u540C\u7684\u6807\u51C6\uFF08\u6BD4\u5982\uFF0C\u8BED\u53E5\u3001\u5206\u652F\u3001\u8DEF\u5F84\u3001\u6761\u4EF6\uFF09\u4ECE\u4E1A\u52A1\u6D41\u7A0B\u6A21\u578B\u521B\u5EFA\u6D4B\u8BD5\u7528\u4F8B\u3002</p><p>\u5B83\u8FD8\u53EF\u4EE5\u4ECE\u591A\u4E2A\u5EFA\u6A21\u5DE5\u5177\u5BFC\u5165\u6A21\u578B\uFF0C\u5E76\u53EF\u4EE5\u5C06\u6D4B\u8BD5\u7528\u4F8B\u5BFC\u51FA\u5230 Excel\u3001HP Quality Center \u7B49\u3002\u8FD9\u4E2A\u5DE5\u5177\uFF0C\u9002\u7528\u4E8E\u4E1A\u52A1\u6D41\u7A0B\u6BD4\u8F83\u6E05\u6670\u76F4\u89C2\u7684\u573A\u666F\u3002</p><p><strong>\u7B2C\u4E8C\uFF0CfMBT</strong></p><p>fMBT \u662F\u4E00\u7EC4\u514D\u8D39\u7684\u3001\u7528\u4E8E\u5168\u81EA\u52A8\u6D4B\u8BD5\u751F\u6210\u548C\u6267\u884C\u7684\u5DE5\u5177\uFF0C\u4E5F\u662F\u4E00\u7EC4\u652F\u6301\u9AD8\u6C34\u5E73\u6D4B\u8BD5\u81EA\u52A8\u5316\u7684\u5B9E\u7528\u7A0B\u5E8F\u548C\u5E93\uFF0C\u4E3B\u8981\u88AB\u5E94\u7528\u5728 GUI \u6D4B\u8BD5\u4E2D\u3002</p><p>fMBT \u5305\u62EC\u7528\u4E8E\u591A\u5E73\u53F0 GUI \u6D4B\u8BD5\u7684 Python \u5E93\uFF0C\u7528\u4E8E\u7F16\u8F91\u3001\u8C03\u8BD5\u3001\u8FD0\u884C\u548C\u8BB0\u5F55 GUI \u6D4B\u8BD5\u811A\u672C\u7684\u5DE5\u5177\uFF0C\u4EE5\u53CA\u7528\u4E8E\u7F16\u8F91\u548C\u53EF\u89C6\u5316\u5206\u6790\u6D4B\u8BD5\u6A21\u578B\u548C\u751F\u6210\u7684\u6D4B\u8BD5\u5DE5\u5177\u3002</p><p><strong>\u7B2C\u4E09\uFF0CGraphWalker</strong></p><p>GraphWalker \u4EE5\u6709\u5411\u56FE\u7684\u5F62\u5F0F\u8BFB\u53D6\u6A21\u578B\uFF0C\u4E3B\u8981\u652F\u6301 FSM\u3001EFSM \u6A21\u578B\u3002\u5B83\u8BFB\u53D6\u8FD9\u4E9B\u6A21\u578B\uFF0C\u7136\u540E\u751F\u6210\u6D4B\u8BD5\u8DEF\u5F84\u3002GraphWalker \u9664\u4E86\u9002\u7528\u4E8E GUI \u6D4B\u8BD5\u5916\uFF0C\u66F4\u9002\u5408\u4E8E\u591A\u72B6\u6001\u4EE5\u53CA\u57FA\u4E8E\u4E8B\u4EF6\u9A71\u52A8\u7684\u72B6\u6001\u8F6C\u6362\u7684\u540E\u53F0\u7CFB\u7EDF\u3002</p><p>\u53E6\u5916\uFF0CGraphWalker \u8FD8\u652F\u6301\u4ECE\u6709\u9650\u72B6\u6001\u673A\u4E2D\u751F\u6210\u6D4B\u8BD5\u7528\u4F8B\u3002</p><p>\u9664\u6B64\u4E4B\u5916\uFF0C\u5E02\u9762\u4E0A\u8FD8\u6709\u5F88\u591A MBT \u6D4B\u8BD5\u5DE5\u5177\uFF0C\u6BD4\u5982 GSL\u3001JSXM\u3001MaTeLo\u3001MBT Suite \u7B49\u3002\u8FD9\u91CC\u5C31\u4E0D\u518D\u4E00\u4E00\u4ECB\u7ECD\u4E86\uFF0C\u4F60\u53EF\u4EE5\u81EA\u884C\u767E\u5EA6\u4E86\u89E3\u5B83\u4EEC\u7684\u7279\u70B9\u548C\u9002\u7528\u573A\u666F\uFF0C\u4ECE\u800C\u9009\u53D6\u5408\u9002\u81EA\u5DF1\u7684\u5DE5\u5177\u3002</p><p><strong>MBT \u7684\u4F18\u52BF</strong></p><p>\u5176\u5B9E\uFF0CMBT \u5E76\u4E0D\u80FD\u7B97\u662F\u4E00\u79CD\u65B0\u9896\u7684\u6D4B\u8BD5\u6280\u672F\uFF0C\u65E9\u5728\u4E03\u516B\u5E74\u524D\u5C31\u5DF2\u7ECF\u88AB\u63D0\u4E86\u51FA\u6765\u5E76\u4E14\u8BD5\u56FE\u5E94\u7528\u4E8E\u8F6F\u4EF6\u4EA7\u54C1\u7684\u6D4B\u8BD5\u5DE5\u4F5C\u4E2D\u3002\u4F46\u662F\uFF0CMBT \u5728\u5F88\u957F\u4E00\u6BB5\u65F6\u95F4\u5185\uFF0C\u5374\u4E00\u76F4\u505C\u7559\u5728\u6982\u5FF5\u9636\u6BB5\uFF0C\u4E3B\u8981\u539F\u56E0\u662F\u4E00\u76F4\u6CA1\u6709\u666E\u9002\u7684\u5DE5\u5177\u652F\u6301\uFF0C\u6240\u4EE5\u5F88\u5C11\u6709\u6210\u529F\u5B9E\u65BD\u7684\u5B9E\u9645\u6848\u4F8B\u3002\u540C\u65F6\uFF0C\u4E1A\u754C\u4E00\u76F4\u4EE5\u6765\u90FD\u7F3A\u4E4F\u9AD8\u6548\u7684\u6D4B\u8BD5\u7528\u4F8B\u8BBE\u8BA1\u751F\u6210\u7B56\u7565\uFF0C\u6240\u4EE5\u867D\u7136\u5927\u5BB6\u90FD\u80FD\u770B\u5230 MBT \u7684\u4F18\u52BF\uFF0C\u4F46\u80FD\u5728\u5B9E\u9645\u9879\u76EE\u4E2D\u5E94\u7528\u6267\u884C\u7684\u5374\u662F\u5BE5\u5BE5\u65E0\u51E0\u3002</p><p>\u4E0E\u4F20\u7EDF\u6D4B\u8BD5\u76F8\u6BD4\uFF0CMBT \u7684\u4F18\u70B9\u5982\u4E0B\uFF1A</p><ol><li>\u6D4B\u8BD5\u7528\u4F8B\u7684\u7EF4\u62A4\u66F4\u8F7B\u677E\u3002\u7531\u4E8E\u6D4B\u8BD5\u7528\u4F8B\u662F\u57FA\u4E8E\u88AB\u6D4B\u7CFB\u7EDF\u7684\u6A21\u578B\u751F\u6210\u7684\uFF0C\u56E0\u6B64\u6211\u4EEC\u53EA\u9700\u7EF4\u62A4\u597D\u6A21\u578B\u5373\u53EF\uFF0C\u800C\u65E0\u9700\u5173\u6CE8\u6D4B\u8BD5\u7528\u4F8B\u7684\u7EC6\u8282\u3002</li><li>\u8F6F\u4EF6\u7F3A\u9677\u53D1\u73B0\u5F97\u66F4\u65E9\u3002\u7531\u4E8E\u6211\u4EEC\u5728\u6784\u5EFA\u88AB\u6D4B\u7CFB\u7EDF\u6A21\u578B\u7684\u8FC7\u7A0B\u4E2D\uFF0C\u5DF2\u7ECF\u5BF9\u88AB\u6D4B\u7CFB\u7EDF\u6709\u4E86\u6BD4\u8F83\u5168\u9762\u7684\u7406\u89E3\uFF0C\u52A0\u4E4B\u8981\u6839\u636E\u7CFB\u7EDF\u9700\u6C42/\u8BF4\u660E\u5B8C\u6210\u5EFA\u6A21\u8FC7\u7A0B\uFF0C\u6240\u4EE5\u6211\u4EEC\u53EF\u4EE5\u5728\u65E9\u671F\u5EFA\u6A21\u65F6\u53D1\u73B0\u88AB\u6D4B\u7CFB\u7EDF\u53EF\u80FD\u5B58\u5728\u7684\u660E\u663E\u7F3A\u9677\uFF0C\u800C\u4E0D\u7528\u7B49\u5230\u6267\u884C\u4E86\u5927\u91CF\u7684\u6D4B\u8BD5\u7528\u4F8B\u4EE5\u540E\u624D\u53D1\u73B0\u8FD9\u4E9B\u7F3A\u9677\u3002</li><li>\u6D4B\u8BD5\u81EA\u52A8\u5316\u7684\u6C34\u5E73\u66F4\u9AD8\u3002\u7531\u4E8E MBT \u53EA\u9700\u5EFA\u597D\u6A21\u578B\u4FBF\u53EF\u4EE5\u81EA\u52A8\u751F\u6210\u6D4B\u8BD5\u7528\u4F8B\uFF0C\u6240\u4EE5\u4E0D\u518D\u9700\u8981\u4EBA\u5DE5\u7F16\u5199\u6D4B\u8BD5\u6587\u6863\u3002\u800C\u66F4\u9AD8\u7EA7\u7684\u5E94\u7528\uFF0C\u751A\u81F3\u53EF\u4EE5\u76F4\u63A5\u751F\u6210\u53EF\u4EE5\u76F4\u63A5\u6267\u884C\u7684\u81EA\u52A8\u5316\u6D4B\u8BD5\u811A\u672C\u3002</li><li>\u6D4B\u8BD5\u8986\u76D6\u7387\u53D8\u5F97\u66F4\u9AD8\uFF0C\u4F7F\u5F97\u5F7B\u5E95\u7684\u6D4B\u8BD5\uFF08\u5373\uFF1A\u7A77\u5C3D\u6D4B\u8BD5\uFF09\u6210\u4E3A\u4E86\u53EF\u80FD\u3002\u7531\u4E8E\u6211\u4EEC\u9700\u8981\u505A\u7684\u53EA\u662F\u6B63\u786E\u3001\u8BE6\u5C3D\u5730\u7528\u6A21\u578B\u63CF\u8FF0\u88AB\u6D4B\u7CFB\u7EDF\uFF0C\u800C\u751F\u6210\u6D4B\u8BD5\u7528\u4F8B\u5B8C\u5168\u7531 MBT \u5DE5\u5177\u5B9E\u73B0\uFF0C\u6240\u4EE5\u8FD9\u5C31\u907F\u514D\u4E86\u4EBA\u5DE5\u8BBE\u8BA1\u6D4B\u8BD5\u7528\u4F8B\u65F6\u7684\u601D\u7EF4\u5C40\u9650\u6027\uFF0C\u80FD\u591F\u6709\u6548\u5730\u63D0\u9AD8\u6D4B\u8BD5\u8986\u76D6\u7387\uFF0C\u8BA9\u5F7B\u5E95\u7684\u6D4B\u8BD5\u53D8\u4E3A\u53EF\u80FD\u3002 \u5F53\u7136\uFF0C\u662F\u5426\u6709\u5FC5\u8981\u5F00\u5C55\u5F7B\u5E95\u7684\u6D4B\u8BD5\u8FD8\u662F\u8981\u7531\u98CE\u9669\u51B3\u5B9A\u3002\u8FD9\u91CC\u7684\u98CE\u9669\u6307\u7684\u662F\uFF0C\u7531\u4E8E\u6F0F\u6D4B\u5BFC\u81F4\u4EA7\u54C1\u95EE\u9898\u5BF9\u4E1A\u52A1\u7684\u5F71\u54CD\u7A0B\u5EA6\u3002MBT \u53EA\u662F\u4ECE\u6280\u672F\u4E0A\u63D0\u4F9B\u4E86\u53EF\u80FD\u6027\u3002</li><li>\u57FA\u4E8E\u6A21\u578B\u95F4\u63A5\u7EF4\u62A4\u6D4B\u8BD5\u7528\u4F8B\u7684\u65B9\u5F0F\u66F4\u9AD8\u6548\u3002\u5728\u4F20\u7EDF\u6D4B\u8BD5\u4E2D\uFF0C\u5982\u679C\u88AB\u6D4B\u7CFB\u7EDF\u7684\u6D41\u7A0B\u6216\u8005\u529F\u80FD\u53D1\u751F\u4E86\u53D8\u5316\uFF0C\u6211\u4EEC\u9700\u8981\u8017\u8D39\u5927\u91CF\u7684\u4EBA\u529B\u548C\u65F6\u95F4\u6210\u672C\uFF0C\u53BB\u91CD\u65B0\u8BBE\u8BA1\u4E0E\u4E4B\u5339\u914D\u7684\u6D4B\u8BD5\u7528\u4F8B\u3002\u800C\u5728 MBT \u4E2D\uFF0C\u6211\u4EEC\u53EA\u9700\u8981\u66F4\u65B0\u88AB\u6D4B\u7CFB\u7EDF\u7684\u6A21\u578B\u5373\u53EF\uFF0C\u5269\u4E0B\u7684\u6D4B\u8BD5\u7528\u4F8B\u751F\u6210\u5DE5\u4F5C\u53EF\u4EE5\u7531 MBT \u5DE5\u5177\u81EA\u52A8\u5B8C\u6210\u3002</li></ol><p><strong>MBT \u7684\u52A3\u52BF</strong></p><p>\u867D\u7136 MBT \u76F8\u5BF9\u4E8E\u4F20\u7EDF\u6D4B\u8BD5\u6709\u5F88\u591A\u4F18\u70B9\uFF0C\u4F46\u5B83\u4E5F\u4E0D\u662F\u5B8C\u7F8E\u7684\u6D4B\u8BD5\u65B9\u6848\u3002\u5728\u5B9E\u9645\u5F00\u5C55 MBT \u65F6\uFF0C\u6211\u4EEC\u5F80\u5F80\u9700\u8981\u5E94\u5BF9\u5F88\u591A\u6311\u6218\uFF0C\u5E76\u514B\u670D\u5F88\u591A\u56F0\u96BE\u3002\u6240\u4EE5\uFF0C\u5230\u73B0\u5728\u4E3A\u6B62\uFF0CMBT \u5E76\u6CA1\u6709\u88AB\u5E7F\u6CDB\u4F7F\u7528\u4E8E\u8F6F\u4EF6\u6D4B\u8BD5\u9886\u57DF\u3002</p><p>\u5728\u8FD9\u91CC\uFF0C\u6211\u603B\u7ED3\u4E86\u5F00\u5C55 MBT \u7684\u4E09\u5927\u96BE\u70B9\uFF1A</p><ol><li><p>\u5B66\u4E60\u6210\u672C\u8F83\u9AD8\u3002MBT \u8981\u6C42\u5F00\u53D1\u4EBA\u5458\u548C\u6D4B\u8BD5\u4EBA\u5458\u90FD\u7CBE\u901A\u5EFA\u6A21\uFF0C\u8FD9\u5C31\u9700\u8981\u4E00\u5B9A\u7684\u57F9\u8BAD\u6210\u672C\uFF0C\u9700\u8981\u8BA9\u5F00\u53D1\u4EBA\u5458\u53BB\u5B66\u4E60\u6D4B\u8BD5\u7684\u6280\u80FD\uFF0C\u8BA9\u6D4B\u8BD5\u4EBA\u5458\u53BB\u5B66\u4E60\u5EFA\u6A21\u6982\u5FF5\u3002\u8FD9\u5176\u4E2D\u8FD8\u7275\u6D89\u5230\u5EFA\u6A21\u5DE5\u5177\u7684\u9009\u62E9\uFF0C\u4EE5\u53CA\u5B66\u4E60\u7B49\u6210\u672C\u3002</p></li><li><p>\u4F7F\u7528 MBT \u7684\u521D\u671F\u6295\u8D44\u8F83\u5927\u3002\u5728\u5F88\u591A\u60C5\u51B5\u4E0B\uFF0C\u6211\u4EEC\u5E76\u4E0D\u80FD\u627E\u5230\u9002\u5408\u81EA\u5DF1\u4EA7\u54C1\u7684\u5EFA\u6A21\u5DE5\u5177\uFF0C\u800C\u9700\u8981\u81EA\u884C\u521B\u5EFA MBT \u5DE5\u5177\u3002 \u5728\u81EA\u884C\u5B9A\u5236 MBT \u5DE5\u5177\u65F6\uFF0C\u6211\u4EEC\u8981\u8003\u8651\u5230\u8FD9\u4E2A\u5DE5\u5177\u5FC5\u987B\u662F\u53EF\u6269\u5C55\u7684\uFF0C\u5E76\u4E14\u80FD\u591F\u5904\u7406\u590D\u6742\u7684\u6D4B\u8BD5\u903B\u8F91\uFF0C\u63D0\u4F9B\u8DB3\u591F\u9AD8\u7684\u6D4B\u8BD5\u8986\u76D6\u7387\uFF0C\u56E0\u6B64\u521A\u5F00\u59CB\u7684\u5DE5\u5177\u5EFA\u8BBE\u5C31\u9700\u8981\u82B1\u8D39\u5927\u91CF\u65F6\u95F4\u548C\u7CBE\u529B\u3002 \u66F4\u7CDF\u7CD5\u7684\u60C5\u51B5\u662F\uFF0C\u5F53\u5DE5\u5177\u5EFA\u597D\u540E\uFF0C\u6211\u4EEC\u5374\u53D1\u73B0\u5B83\u5E76\u4E0D\u80FD\u6EE1\u8DB3\u6240\u6709\u7684\u5EFA\u6A21\u9700\u6C42\uFF0C\u56E0\u6B64\u8FD8\u8981\u5728\u5EFA\u6A21\u7684\u540C\u65F6\u5BF9\u5DE5\u5177\u8FDB\u884C\u5FAE\u8C03\u3002\u800C\uFF0C\u8FD9\u79CD\u5FAE\u8C03\u5DE5\u4F5C\u7684\u96BE\u5EA6\uFF0C\u4E5F\u6BD4\u8F83\u5927\u3002</p></li><li><p>\u65E9\u671F\u6839\u636E\u6A21\u578B\u751F\u6210\u6D4B\u8BD5\u7528\u4F8B\u7684\u6280\u672F\u5E76\u4E0D\u662F\u975E\u5E38\u6210\u719F\u3002\u5F88\u591A\u65F6\u5019\u53EA\u662F\u6839\u636E\u56FE\u8BBA\u7684\u7B97\u6CD5\u6765\u904D\u5386\u6A21\u578B\uFF0C\u8FD9\u5C31\u4F1A\u5BFC\u81F4\u751F\u6210\u7684\u5F88\u591A\u6D4B\u8BD5\u7528\u4F8B\u5728\u4E1A\u52A1\u4E0A\u6839\u672C\u6CA1\u6709\u4EFB\u4F55\u5B9E\u9645\u610F\u4E49\uFF0C\u4E5F\u56E0\u6B64\u963B\u788D\u4E86 MBT \u5728\u5B9E\u9645\u9879\u76EE\u4E2D\u7684\u843D\u5730\u3002 \u4E0D\u8FC7\u597D\u5728\u8FD1\u4E00\u4E24\u5E74\u6765\uFF0C\u57FA\u4E8E\u4EBA\u5DE5\u667A\u80FD\uFF08AI\uFF09\u751F\u6210\u6D4B\u8BD5\u7528\u4F8B\u7684\u6982\u5FF5\u4E0D\u65AD\u6210\u719F\uFF0C\u6240\u4EE5\u5C06\u57FA\u4E8E AI \u7684\u6D4B\u8BD5\u7528\u4F8B\u751F\u6210\u548C MBT \u76F8\u7ED3\u5408\uFF0C\u5C06\u4F1A\u662F\u63A5\u4E0B\u6765\u7684\u4E00\u4E2A\u53D1\u5C55\u65B9\u5411\u3002</p></li></ol><p>\u603B\u7684\u6765\u8BF4\uFF0CMBT \u548C\u4F20\u7EDF\u6D4B\u8BD5\u5404\u6709\u4F18\u52A3\u3002\u6240\u4EE5\uFF0C\u6D4B\u8BD5\u7684\u65B9\u6CD5\u591A\u79CD\u591A\u6837\uFF0CMBT \u53EA\u662F\u5176\u4E2D\u7684\u4E00\u79CD\u3002</p><p>\u5982\u679C\u4E00\u4E2A\u5E94\u7528\u7684\u4EFB\u4F55\u7EC4\u4EF6\u90FD\u53EF\u4EE5\u901A\u8FC7\u6A21\u578B\u6765\u6A21\u62DF\u3001\u901A\u8FC7\u9A71\u52A8\u7A0B\u5E8F\u6765\u9A71\u52A8\uFF0C\u5E76\u53EF\u4EE5\u901A\u8FC7\u6D4B\u8BD5\u7ED3\u679C\u6765\u6BD4\u8F83\u7684\u8BDD\uFF0C\u90A3\u4E48\u8FD9\u4E2A\u5E94\u7528\u5C31\u662F MBT \u7684\u6700\u4F73\u5019\u9009\u8005\u3002</p><p>\u5982\u679C\u6211\u4EEC\u7684\u4EA7\u54C1\u7279\u5F81\u7B26\u5408\u5F00\u5C55 MBT \u7684\u8981\u6C42\uFF0C\u5E76\u4E14\u56E2\u961F\u5404\u65B9\u9762\u7684\u6761\u4EF6\u90FD\u652F\u6301\u4F7F\u7528 MBT \u65F6\uFF0C\u6211\u4EEC\u4FBF\u53EF\u4EE5\u5C1D\u8BD5\u7528\u8FD9\u79CD\u65B9\u6CD5\u6765\u6539\u9769\u6211\u4EEC\u7684\u6D4B\u8BD5\u65B9\u5F0F\u3002\u5C24\u5176\u662F\u5C06 MBT \u7ED3\u5408\u57FA\u4E8E AI \u7684\u6D4B\u8BD5\u7528\u4F8B\u751F\u6210\u6280\u672F\uFF0C\u5C06\u53EF\u4EE5\u5927\u5927\u52A0\u901F MBT \u4EA7\u4E1A\u5E94\u7528\u7684\u6B65\u4F10\u3002</p><p>\u4F46\u662F\uFF0C\u4E0D\u7BA1\u662F\u5426\u91C7\u7528 MBT\uFF0C\u5F00\u53D1\u4EBA\u5458\u6216\u6D4B\u8BD5\u4EBA\u5458\u5728\u63A5\u89E6\u5230\u4E00\u6B3E\u8F6F\u4EF6\u4EA7\u54C1\u65F6\uFF0C\u9996\u5148\u90FD\u4F1A\u6709\u4E00\u4E2A\u5FC3\u7406\u5EFA\u6A21\u7684\u8FC7\u7A0B\uFF0C\u81EA\u5DF1\u5148\u53BB\u7406\u89E3\u5E76\u5728\u8111\u4E2D\u52FE\u52D2\u51FA\u7CFB\u7EDF\u7684\u529F\u80FD\u7ED3\u6784\u548C\u6D41\u7A0B\u3002\u5176\u5B9E\uFF0C\u8FD9\u4E9B\u5185\u5BB9\u5F88\u5BB9\u6613\u5C31\u53EF\u4EE5\u8F6C\u6362\u6210\u5B9E\u9645\u7684\u6A21\u578B\uFF0C\u4E5F\u5C31\u4E3A MBT \u521B\u9020\u4E86\u6761\u4EF6\u3002</p><p><strong>\u603B\u7ED3</strong></p><p>\u4ECA\u5929\uFF0C\u6211\u548C\u4F60\u5206\u4EAB\u4E86 MBT \u7684\u57FA\u672C\u6982\u5FF5\u548C\u65B9\u6CD5\u3002</p><p>MBT \u662F\u4E00\u79CD\u57FA\u4E8E\u88AB\u6D4B\u7CFB\u7EDF\u7684\u6A21\u578B\uFF0C\u7531\u5DE5\u5177\u81EA\u52A8\u751F\u6210\u6D4B\u8BD5\u7528\u4F8B\u7684\u8F6F\u4EF6\u6D4B\u8BD5\u6280\u672F\u3002\u6240\u4EE5\uFF0C\u8FD9\u4E5F\u5C31\u51B3\u5B9A\u4E86 MBT \u76F8\u5BF9\u4E8E\u4F20\u7EDF\u6D4B\u8BD5\u6280\u672F\u53EF\u4EE5\u5728\u6D4B\u8BD5\u7528\u4F8B\u7EF4\u62A4\u3001\u8F6F\u4EF6\u7F3A\u9677\u53D1\u73B0\u65F6\u673A\u3001\u6D4B\u8BD5\u81EA\u52A8\u5316\u6C34\u5E73\uFF0C\u4EE5\u53CA\u6D4B\u8BD5\u8986\u76D6\u7387\u7B49\u65B9\u9762\u6709\u5176\u72EC\u5230\u7684\u4F18\u52BF\u3002</p><p>\u4F46\u540C\u65F6\uFF0C\u8FD9\u4E5F\u4F7F\u5F97 MBT \u76F8\u5BF9\u4E8E\u4F20\u7EDF\u8F6F\u4EF6\u6D4B\u8BD5\uFF0C\u5728\u521D\u671F\u9636\u6BB5\u6295\u5165\u8F83\u5927\uFF0C\u5B66\u4E60\u5E94\u7528\u7684\u6210\u672C\u8F83\u9AD8\u3002\u4E5F\u6B63\u56E0\u4E3A\u5982\u6B64\uFF0CMBT \u6982\u5FF5\u867D\u7136\u5DF2\u7ECF\u63D0\u51FA\u4E86\u4E03\u516B\u5E74\u7684\u65F6\u95F4\uFF0C\u4F46\u5374\u5E76\u6CA1\u6709\u88AB\u5E7F\u6CDB\u5E94\u7528\u4E8E\u8F6F\u4EF6\u6D4B\u8BD5\u9886\u57DF\u3002</p><p>\u6240\u4EE5\uFF0C\u5173\u4E8E\u662F\u5426\u8981\u5728\u81EA\u5DF1\u7684\u9879\u76EE\u4E2D\u5F00\u5C55 MBT\uFF0C\u6211\u4EEC\u9700\u8981\u7EFC\u5408\u8003\u8651\u9879\u76EE\u672C\u8EAB\u7684\u7279\u70B9\u548C\u4EBA\u5458\u7684\u6280\u672F\u6C34\u5E73\uFF0C\u4EE5\u6B64\u51B3\u5B9A\u662F\u5426\u6709\u5FC5\u8981\u5F00\u5C55 MBT\u3002</p><p><strong>\u601D\u8003\u9898</strong></p><p>\u5047\u5982\u4F60\u8981\u5728\u9879\u76EE\u4E2D\u5F00\u5C55 MBT\uFF0C\u4F60\u4F1A\u5982\u4F55\u5224\u65AD\u4F60\u7684\u9879\u76EE\u662F\u5426\u9002\u5408\u91C7\u7528 MBT\uFF0C\u4EE5\u53CA\u4F60\u8BA4\u4E3A\u4F1A\u9047\u5230\u54EA\u4E9B\u95EE\u9898\u53EF\u80FD\u4F1A\u963B\u788D MBT \u7684\u5F00\u5C55\u5462\uFF1F</p>',67);function r(t,e){return T}var s=p(B,[["render",r],["__file","47.html.vue"]]);export{s as default};
